"""
MKT Christ Commentary — Judges chapters 1–3
Run: python3 scripts/zc-christ-judges-1-3-fill.py

Source data used:
- data/interlinear/judges.json
- data/translation/draft/mediating/judges.json
- data/commentary/mkt-christ/judges.json (v2:16 already present)

Key decisions in this range:
- Ch1 incomplete conquest: cumulative failure as shadow of the need for a perfect deliverer
- Achsah/springs (1:14-15): water-gift motif as shadow pointing to living water (John 7:37)
- Othniel (3:9-11): cleanest judge-type; Spirit-anointing anticipates Christ at baptism
- Ehud's left-handedness (3:15): divine choice of the weak (1 Cor 1:27)
- Shamgar's oxgoad (3:31): extraordinary deliverance through unexpected means
- Angel of YHWH at Bochim (2:1): theophanic appearance; covenant reaffirmed by YHWH himself
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JUDGES = {
  "1": {
    "1": "<p>A theme: the death of Joshua creates a leadership vacuum — the same pattern that will repeat throughout Judges. Israel inquires of YHWH who shall go up first, pointing to the ongoing need for divine direction after every human deliverer passes. The recurring vacancy of leadership points forward to Christ as the one leader who does not die and leave a successor problem (Heb 7:24: &ldquo;he holds his priesthood permanently, because he continues forever&rdquo;).</p>",
    "2": "<p>A theme: YHWH&rsquo;s commission of Judah anticipates the messianic trajectory. Judah is the tribe designated for kingship (Gen 49:8-10: &ldquo;the scepter shall not depart from Judah&rdquo;); the command that Judah go first frames the entire conquest as Judah&rsquo;s lead role, fulfilled ultimately in Jesus, the Lion of the tribe of Judah (Rev 5:5). The gift-formula &ldquo;I have given the land into his hand&rdquo; declares the outcome before the battle, the same divine confidence expressed in Christ&rsquo;s resurrection before the cross.</p>",
    "3": "<p>A theme: Judah and Simeon act together as a covenant-community sharing the same task. The mutual inheritance dynamic (&ldquo;you shall come with me into my allotted territory, and I also will go with you into yours&rdquo;) anticipates the NT vision of mutual participation in one another&rsquo;s inheritance in Christ (Eph 3:6: Gentiles are &ldquo;fellow heirs&rdquo;).</p>",
    "4": "<p>A theme: &ldquo;the LORD gave the Canaanites and the Perizzites into their hand&rdquo; — divine warfare. The pattern of YHWH as the true military actor behind every Israelite victory anticipates Christ as the warrior who defeats every enemy through his resurrection (Col 2:15: &ldquo;having disarmed the rulers and authorities, he put them to open shame, by triumphing over them in him&rdquo;).</p>",
    "5": "<p>A theme: Adoni-bezek (&ldquo;lord of Bezek&rdquo;) is defeated at Bezek. The defeat of entrenched pagan power structures by Judah&rsquo;s armies is a partial, temporal fulfillment of the promise that all hostile powers will be brought low. The NT presents Christ as the one before whom every knee bows and every lord of the earth is subdued (Phil 2:10-11).</p>",
    "6": "<p>A theme: the mutilation of Adoni-bezek — cutting off his thumbs and big toes — disabled him for both war and worship (Levitical law barred the blemished from priestly service). The systematic humiliation of the enemy ruler anticipates the final defeat of all hostile powers; Ps 110:1 (&ldquo;until I make your enemies your footstool&rdquo;) governs the entire conquest narrative.</p>",
    "7": "<p>A revelation of God: Adoni-bezek&rsquo;s own confession — &ldquo;as I have done, so God has repaid me&rdquo; — acknowledges the divine lex talionis: evil returns on itself. This principle of divine retributive justice is the same framework within which the cross operates: Christ absorbs the retribution that sinners deserve so that the law of divine justice is fully satisfied (Rom 3:25-26) rather than bypassed.</p>",
    "8": "<p>A shadow: Judah takes Jerusalem and burns it, yet the city remains contested and is not permanently held (v21: Benjamin cannot drive out the Jebusites). Jerusalem&rsquo;s incomplete capture under human leadership shadows its ultimate meaning: the city is fully claimed only when David takes it (2 Sam 5:6-9) and ultimately when Christ enters it as its true king. The city&rsquo;s contested history points to the tension between partial human achievement and final divine fulfillment.</p>",
    "9": "<p>A theme: the extension of the campaign to the hill country, Negeb, and Shephelah fills out the promised boundaries of Judah&rsquo;s territory. The breadth of the promised inheritance anticipates the &ldquo;all things&rdquo; given to the Son (Matt 11:27; 28:18), though its full possession awaits the eschatological age.</p>",
    "10": "<p>A theme: Judah goes against Hebron — the city of the patriarchs, burial site of Abraham, Isaac, and Jacob. The conquest of Hebron represents reclaiming the ground where the covenant was anchored; the three sons of Anak are defeated. The defeat of the giants who held the ancestral land mirrors the defeat of every power that occupies what belongs to God&rsquo;s people by covenant.</p>",
    "11": "<p>A theme: Debir (formerly Kiriath-sepher, &ldquo;city of the book&rdquo;) is taken. The capture of the city of scribes or books carries symbolic weight: the defeat of learned paganism; the true wisdom of YHWH displacing the city of letters. The NT presents Christ as the one in whom &ldquo;all the treasures of wisdom and knowledge are hidden&rdquo; (Col 2:3).</p>",
    "12": "<p>A type: Caleb offers his daughter Achsah as a prize to whoever captures Debir. Othniel wins and receives her. The pattern — a great man offers his daughter to the one who defeats a formidable enemy — structurally anticipates the Father offering the church as bride to Christ, who defeats every enemy to claim her (Eph 5:25-27; Rev 19:7-9).</p>",
    "13": "<p>A type: Othniel the son of Kenaz captures the city and wins the bride. He will reappear as the first and cleanest judge-type in Judges 3:9-11. His victory here — accomplishing through courage and warfare what makes him worthy to receive the gift of Achsah — anticipates Christ winning the church through his conquest of sin and death.</p>",
    "14": "<p>A shadow: Achsah urges her husband to ask her father for a field. She then dismounts from her donkey and makes her own request of Caleb. The image of the bride approaching the father to ask for what she needs points forward to the church&rsquo;s intercessory prayer life: access to the Father&rsquo;s resources through the mediation of the Son, and the Spirit&rsquo;s help in making requests (Rom 8:26-27).</p>",
    "15": "<p>A shadow: Achsah asks for &ldquo;springs of water&rdquo; — the upper springs and the lower springs. Her father gives her both. The gift of water from the one who holds the land anticipates the living water that Christ gives: &ldquo;whoever drinks of the water that I will give him will never be thirsty again&rdquo; (John 4:14); &ldquo;rivers of living water will flow from his innermost being&rdquo; (John 7:38). Achsah recognizes her need and asks; the father gives abundantly.</p>",
    "16": "<p>A theme: the Kenites (descendants of Moses&rsquo; father-in-law) join Judah and settle in the Negeb near Arad. The inclusion of non-Israelites who align with YHWH&rsquo;s purposes anticipates the Gentile incorporation into the covenant community. The Kenites were not part of the twelve tribes; their participation in the inheritance points toward the day when &ldquo;there is neither Jew nor Greek&rdquo; (Gal 3:28).</p>",
    "17": "<p>A theme: Judah and Simeon devote Zephath to destruction, renaming it Hormah (&ldquo;devoted to destruction&rdquo;). The <em>ḥērem</em> (holy war ban) is the complete consecration of the enemy to YHWH, leaving nothing for Israel to keep. This radical act of consecration anticipates the ultimate elimination of all that opposes God&rsquo;s kingdom — the final judgment in which nothing unholy remains (Rev 21:27).</p>",
    "18": "<p>A theme: the capture of the Philistine coastal cities — Gaza, Ashkelon, Ekron — is listed without elaboration. These will be contested throughout Judges and into the monarchy period. The partial victories point to the ongoing warfare of the covenant community in a not-yet-fully-redeemed world; the final defeat of Philistia stands as a metaphor for the defeat of all hostile powers still at work.</p>",
    "19": "<p>A shadow: &ldquo;the LORD was with Judah, and he took possession of the hill country, but he could not drive out the inhabitants of the plain because they had iron chariots.&rdquo; The divine presence does not eliminate all obstacles; partial success remains. This limitation of every human leader — even one accompanied by YHWH — shadows the need for a deliverer who can overcome every enemy, including the ultimate enemies of sin and death that no human soldier can defeat.</p>",
    "20": "<p>A theme: Hebron is given to Caleb as Moses had promised (Num 14:24). Caleb&rsquo;s faithful reception of his inheritance decades after the promise — after years of wilderness wandering and incomplete conquest — is a model of patient faith. He received what was promised to him because he &ldquo;wholly followed the LORD.&rdquo; Heb 6:12 calls believers to imitate those who &ldquo;through faith and patience inherit the promises.&rdquo;</p>",
    "21": "<p>A shadow: Benjamin&rsquo;s failure to drive out the Jebusites means they &ldquo;live with the people of Benjamin in Jerusalem to this day.&rdquo; Jerusalem remains a city with a pagan presence until David&rsquo;s conquest (2 Sam 5:6-9). This ongoing Jebusite presence in the city of the future king and temple shadows the incomplete nature of all pre-messianic redemption; only Christ fully cleanses and reclaims what belongs to God.</p>",
    "22": "<p>A theme: &ldquo;the LORD was with them&rdquo; — the house of Joseph takes Bethel. Divine presence is the decisive factor in all conquest, all ministry, all redemptive work. The NT promises the same presence to Christ&rsquo;s disciples: &ldquo;I am with you always, to the end of the age&rdquo; (Matt 28:20).</p>",
    "23": "<p>A theme: scouts are sent to Bethel (formerly Luz). The reconnaissance pattern — sending ahead to know the way — anticipates John the Baptist, who is sent ahead of Christ to prepare the way (Mal 3:1; Luke 1:76).</p>",
    "24": "<p>A shadow: the spies ask the man coming out of the city to show them the way in, and promise kindness in return. The informer cooperates with Israel&rsquo;s purposes and his household is spared — the same mercy-for-cooperation pattern as Rahab (Josh 2). Those who open the way for YHWH&rsquo;s work receive covenant protection.</p>",
    "25": "<p>A theme: the city is struck, but the informer and his household are let go. The preserving of faithful individuals within a condemned city (cf. Noah, Lot, Rahab) anticipates the NT doctrine of divine election: &ldquo;the Lord knows those who are his&rdquo; (2 Tim 2:19) and will preserve them through judgment.</p>",
    "26": "<p>A theme: the man goes to build a new city named Luz — he recreates his former life outside the covenant community. The continuing existence of Luz as a pagan city serves as a reminder that the covenant community does not save everyone it contacts; those outside it carry their own identity. The universality of salvation&rsquo;s offer does not override individual response.</p>",
    "27": "<p>A shadow: Manasseh&rsquo;s failure to drive out the inhabitants of Beth-shean, Taanach, Dor, Ibleam, and Megiddo initiates the long list of incomplete conquests (vv.27-36). Each tribe&rsquo;s partial obedience accumulates to reveal a systemic human incapacity for holy war. The incomplete conquest is not an accident; it shadows the deeper truth that no human effort can achieve complete redemption — that requires the one whose conquest of sin and death is total and final.</p>",
    "28": "<p>A theme: when Israel grew strong they put Canaanites to forced labor rather than driving them out. The compromise of pragmatism over obedience — using the enemy rather than defeating them — is the root of Israel&rsquo;s later apostasy. The pattern warns against the NT temptation to accommodate sin rather than mortify it (Rom 8:13; Col 3:5).</p>",
    "29": "<p>A shadow: Ephraim&rsquo;s failure at Gezer continues the pattern. Gezer will remain a Canaanite city until Solomon&rsquo;s day, when Pharaoh gives it as a dowry for his daughter (1 Kgs 9:16-17). Even then its final resolution comes through a foreign king&rsquo;s gift rather than Israel&rsquo;s obedience — a pointed commentary on the limits of the Solomonic kingdom that points beyond itself to Christ&rsquo;s complete dominion.</p>",
    "30": "<p>A theme: Zebulun&rsquo;s failure at Kitron and Nahalol — the Canaanites live among them rather than being expelled. The reversal of the intended order (Israel living among Canaanites rather than Canaanites being expelled) mirrors the danger of letting the world&rsquo;s values remain entrenched within the covenant community.</p>",
    "31": "<p>A theme: Asher&rsquo;s long list of failures (Acco, Sidon, Ahlab, Achzib, Helbah, Aphik, Rehob) is the most extensive. Asher lives among the Canaanites rather than expelling them — the complete inversion of the divine command. The accumulating weight of these failures across all the tribes establishes beyond doubt that human Israel cannot achieve what God requires; a perfect obedience from outside the fallen system is necessary.</p>",
    "32": "<p>A shadow: the text explicitly notes the Asherites lived <em>among</em> the Canaanites — the Canaanites are no longer the minority being absorbed but the dominant culture absorbing Israel. This inversion — the covenant community absorbed into surrounding paganism — is the pattern that Judges will document through the judge cycles. It finds its redemptive reversal in Christ, who enters the corrupt world not to be conformed to it but to transform it (Rom 12:2; John 17:15-18).</p>",
    "33": "<p>A theme: Naphtali&rsquo;s failure at Beth-shemesh (house of the sun) and Beth-anath — both cities bearing names of Canaanite deities — signals that the failure is not merely military but spiritual. Israel was meant to displace the worship of false gods; instead the worship-centers of Baal and Anat remain intact in their territory.</p>",
    "34": "<p>A theme: Dan is pushed back by the Amorites and hemmed in — the only tribe that does not merely fail to drive out enemies but is actively displaced by them. Dan&rsquo;s territorial vulnerability anticipates their later migration in Judges 18. The powerlessness of the tribe in the face of iron-armed opposition underscores that human weakness requires divine empowerment; without YHWH, even covenant people are driven back.</p>",
    "35": "<p>A theme: the Amorites persist at Mount Heres and Aijalon until &ldquo;the hand of the house of Joseph&rdquo; grew heavy against them — military pressure rather than obedience-to-divine-command eventually brought partial resolution. The pragmatic outcome (forced labor) mirrors the compromise of v28. The theme of &ldquo;the hand&rdquo; (<em>yād</em>) becoming strong only by human effort, not divine calling, contrasts with the judges&rsquo; Spirit-empowered victories.</p>",
    "36": "<p>A theme: the chapter closes with the territorial boundary of the Amorites — they are still there, defining the edges of unconquered territory. The closing geographical notation underscores the chapter&rsquo;s thesis: the conquest is incomplete, and the boundaries of failure are now mapped. This sets the stage for Judges&rsquo; central argument: human obedience cannot achieve the complete inheritance; only divine intervention through Spirit-empowered deliverers can, and even they are temporary. Christ alone permanently establishes the boundary of the kingdom.</p>"
  },
  "2": {
    "1": "<p>A type: the Angel of the LORD ascending from Gilgal to Bochim is YHWH himself in theophanic form (cf. Judg 6:11-24; 13:2-22 where the Angel is recognized as God). He reaffirms the covenant — &ldquo;I brought you up from Egypt and I brought you into the land&rdquo; — and announces the consequences of disobedience. The Angel of the LORD who mediates covenant history is the same divine Person who appears in Christ: Jn 1:18 (&ldquo;the only Son, who is at the Father&rsquo;s side, has made him known&rdquo;).</p>",
    "2": "<p>A theme: the covenant requirements — no covenant with the inhabitants, break down their altars — were not kept. The total demand of the covenant (exclusive allegiance, destruction of competing worship) mirrors the NT demand of total consecration to Christ: &ldquo;Do not be unequally yoked with unbelievers&rdquo; (2 Cor 6:14); &ldquo;you cannot serve God and money&rdquo; (Matt 6:24). The impossibility of perfect covenant-keeping by human effort points to the need for a covenant partner who will keep it on behalf of his people.</p>",
    "3": "<p>A theme: the nations become &ldquo;thorns in your sides&rdquo; and &ldquo;their gods will be a snare to you.&rdquo; The consequence of incomplete obedience is ongoing trouble from what was not fully dealt with. This pattern of unresolved sin becoming a persistent snare is addressed in Christ&rsquo;s complete atonement: he not only forgives but destroys the power of sin (1 Jn 3:8: &ldquo;The Son of God appeared to destroy the works of the devil&rdquo;).</p>",
    "4": "<p>A revelation of God: Israel weeps (<em>wayyiśśəʾû qôlām wayyiḇkû</em>) when confronted with their covenant failure. The divine word, when faithfully delivered, produces genuine mourning over sin — the godly grief that leads to repentance (2 Cor 7:10). Christ&rsquo;s proclamation similarly produces grief that leads to life: the Beatitude &ldquo;blessed are those who mourn, for they shall be comforted&rdquo; (Matt 5:4) names this as a mark of kingdom citizens.</p>",
    "5": "<p>A theme: the place is named Bochim (&ldquo;weepers&rdquo;) and they sacrifice to YHWH there. The naming of a place by the spiritual experience that occurred there is an OT pattern of memorial — these places function as reminders of divine encounter and covenant reckoning. The sacrifices at Bochim anticipate the sacrifice of Christ, in whom every divine-human reconciliation finds its ground.</p>",
    "6": "<p>A theme: Joshua dismisses the people to their inheritances. The covenant community scattered to receive what has been allotted to them mirrors the NT vision of the church scattered into the world to occupy their calling while waiting for the full inheritance. Each tribe&rsquo;s inheritance is a partial anticipation of the &ldquo;inheritance that is imperishable, undefiled, and unfading, kept in heaven&rdquo; (1 Pet 1:4).</p>",
    "7": "<p>A theme: the people served YHWH all the days of Joshua and the elders who outlived him — those who had seen YHWH&rsquo;s work. Faithfulness is easier when living witnesses of divine action are present. The NT community is called to continue in faith beyond the eyewitness generation: &ldquo;blessed are those who have not seen and yet have believed&rdquo; (Jn 20:29). The Spirit&rsquo;s role in maintaining faith across generations (replacing the eyewitness function) is the guarantee of this continuity.</p>",
    "8": "<p>A theme: Joshua &ldquo;the servant of the LORD&rdquo; (<em>ʿeḇed YHWH</em>) dies at 110 — the same age as Joseph (Gen 50:26). The <em>ʿeḇed YHWH</em> title connects Joshua to the Servant Songs of Isaiah; Joshua is a faithful servant who accomplishes his mission and dies. Isaiah&rsquo;s Servant (Isa 53) also dies — but in his death accomplishes the ultimate redemptive mission, and unlike Joshua, he does not leave a void of leadership.</p>",
    "9": "<p>A theme: Joshua is buried at Timnath-heres (or Timnath-serah; &ldquo;portion of the sun&rdquo;) in the hill country of Ephraim. Every deliverer is eventually buried, and the community must continue without them. Only Christ — buried and then raised — provides a continuing leadership that does not depend on successors (Heb 7:25: &ldquo;he always lives to make intercession for them&rdquo;).</p>",
    "10": "<p>A shadow: &ldquo;There arose another generation after them who did not know the LORD or the work that he had done for Israel.&rdquo; This spiritual amnesia is the root of the judge cycle. The new covenant addresses this structural vulnerability: &ldquo;I will put my law within them, and I will write it on their hearts&rdquo; (Jer 31:33); the Spirit is given so that each believer has direct knowledge of God, not merely inherited tradition (1 Jn 2:27).</p>",
    "11": "<p>A theme: Israel abandons YHWH and serves the Baals. The shift from the living God to fertility-deity worship is the archetypal apostasy; &ldquo;doing what was evil in the sight of the LORD&rdquo; is the Deuteronomistic judgment formula. The NT frames idolatry similarly: &ldquo;flee from idolatry&rdquo; (1 Cor 10:14); &ldquo;guard yourselves from idols&rdquo; (1 Jn 5:21). Idolatry&rsquo;s deepest form is whatever displaces Christ as the center of one&rsquo;s devotion.</p>",
    "12": "<p>A theme: they abandoned YHWH &ldquo;who had brought them out of the land of Egypt&rdquo; — the Exodus redemption is the anchor of covenant identity, and to abandon YHWH is to abandon one&rsquo;s origin and identity. Paul uses the same logic for NT believers: abandoning Christ is to forget that you were &ldquo;bought with a price&rdquo; (1 Cor 6:20), that you were redeemed from slavery to sin.</p>",
    "13": "<p>A theme: &ldquo;they abandoned the LORD and served Baal and the Ashtoreths.&rdquo; The Ashtoreths (fertility goddesses) represent the reduction of divine worship to the management of natural cycles and human prosperity. The prophets repeatedly describe this as spiritual adultery (Hosea 1-3; Ezek 16). Christ&rsquo;s claim to be the resurrection and the life (Jn 11:25) — not merely the manager of fertility and fortune — is the antidote to this reduction.</p>",
    "14": "<p>A revelation of God: YHWH&rsquo;s anger is not passive or impotent — he sells them into the hand of plunderers and gives them over to their enemies. Divine discipline is an expression of covenant love (Heb 12:6: &ldquo;the Lord disciplines the one he loves&rdquo;). The same God who delivers also permits difficulty when his people persist in covenant unfaithfulness; both actions serve the purpose of restoring the relationship.</p>",
    "15": "<p>A revelation of God: &ldquo;the hand of the LORD was against them for harm, as the LORD had warned, and they were in terrible distress.&rdquo; The covenant curses of Deut 28 are activated. The wrath of God against covenant unfaithfulness is real — and it is precisely this wrath that Christ absorbs on the cross (Rom 3:25; Gal 3:13), so that those who are in him are no longer under the covenant curse.</p>",
    "17": "<p>A shadow: even after judges were raised up, the people &ldquo;did not listen to their judges, for they whored after other gods.&rdquo; Every human deliverer is ultimately ineffective at producing lasting covenant faithfulness. The judge-cycle&rsquo;s escalating corruption — &ldquo;they were more corrupt than their fathers&rdquo; (v19) — demonstrates that external deliverance cannot change the heart. The new covenant&rsquo;s promise of inner transformation (Ezek 36:26-27) is the only solution to the cycle that Judges documents.</p>",
    "18": "<p>A type: &ldquo;whenever the LORD raised up judges for them, the LORD was with the judge, and he saved them from the hand of their enemies all the days of the judge.&rdquo; This verse distills the judge-type: raised up by YHWH, accompanied by divine presence, delivering from enemies, providing rest during their tenure. Every element maps onto Christ — raised up by the Father (Acts 2:32), the divine presence incarnate (Matt 1:23), the deliverer from all enemies (Col 2:15), the one in whom the Sabbath-rest of God is found (Matt 11:28-30).</p>",
    "19": "<p>A shadow: &ldquo;whenever the judge died, they turned back and were more corrupt than their fathers.&rdquo; The death of each judge undoes the deliverance; the cycle restarts and deepens in depravity. This structural problem — the deliverer&rsquo;s death reverses his work — is resolved only in Christ whose death does not undo but accomplishes his saving work, and whose resurrection means his deliverance cannot be reversed (Rom 6:9: &ldquo;Christ, being raised from the dead, will never die again&rdquo;).</p>",
    "20": "<p>A revelation of God: YHWH&rsquo;s anger is expressed in covenantal terms: &ldquo;this people has transgressed my covenant that I commanded their fathers.&rdquo; The violation is relational — covenant, not merely legal — and YHWH&rsquo;s response is relational discipline. The new covenant established in Christ&rsquo;s blood (Luke 22:20) does not abolish the covenantal structure but fulfills it: Christ perfectly keeps the covenant on behalf of his people (2 Cor 1:20).</p>",
    "21": "<p>A theme: YHWH will no longer drive out the remaining nations — their presence will serve as a test. The nations left in the land become the means of sanctification: Israel must choose faithfulness under pressure. The NT parallel is the continuing presence of temptation and opposition in the believer&rsquo;s life, which God permits not because he is absent but because it produces mature faith (Jas 1:2-4; Rom 5:3-4).</p>",
    "22": "<p>A theme: the nations remain &ldquo;in order to test Israel by them, whether they will take care to walk in the way of the LORD as their fathers did.&rdquo; Testing as a divine pedagogical instrument runs throughout Scripture: Abraham&rsquo;s testing (Gen 22), Israel in the wilderness (Deut 8:2), Jesus&rsquo; temptation in the wilderness (Matt 4:1). Christ&rsquo;s perfect obedience through testing establishes the standard that the new covenant makes available to believers through the Spirit.</p>",
    "23": "<p>A theme: YHWH &ldquo;left those nations, not driving them out quickly.&rdquo; The divine patience in not immediately resolving every opposition — giving time for covenant engagement and testing — mirrors the eschatological patience of the NT: &ldquo;the Lord is not slow to fulfill his promise as some count slowness, but is patient toward you, not wishing that any should perish&rdquo; (2 Pet 3:9). The incompleteness of the present age is purposeful.</p>"
  },
  "3": {
    "1": "<p>A theme: the nations left are enumerated — the five lords of the Philistines, the Canaanites, Sidonians, and Hivites. Their persistent presence is YHWH&rsquo;s deliberate provision of a testing environment for generations of Israelites who had not experienced the Exodus wars. The NT presents believers similarly as resident aliens in a world where opposition remains (1 Pet 2:11-12) — the testing environment is the school of covenant maturity.</p>",
    "2": "<p>A theme: the nations are left so that &ldquo;the generations of the people of Israel might know war, to teach it to those who had not known it before.&rdquo; Spiritual combat requires learning; the faith that overcomes the world (1 Jn 5:4) is formed through engagement with opposition. Christ himself learned obedience through what he suffered (Heb 5:8), and the pattern of growth through struggle is central to the NT discipleship vision.</p>",
    "3": "<p>A theme: the five Philistine lords — Gaza, Ashdod, Ashkelon, Gath, Ekron — plus the Canaanites and Sidonians and Hivites remain. The identification of specific adversaries matters: they are not abstract evil but concrete historical opponents with territories and rulers. The NT is equally concrete about spiritual adversaries (Eph 6:12) — the Christian&rsquo;s battle is not against vague forces but against specific principalities that have real hold in the world.</p>",
    "4": "<p>A theme: their purpose is stated explicitly — &ldquo;to test Israel, to know whether Israel would obey the commandments of the LORD.&rdquo; The test reveals what is already present but hidden: obedience or disobedience, faith or faithlessness. The testing by adversaries in the NT similarly reveals the quality of faith (1 Pet 1:7: &ldquo;the tested genuineness of your faith, more precious than gold&rdquo;), and Christ himself was tested to demonstrate the quality of his obedience (Matt 4:1-11).</p>",
    "5": "<p>A shadow: Israel lives <em>among</em> the Canaanites — the reversal of the intended order. Instead of driving them out, Israel is surrounded. The pastoral situation assumes co-habitation with those whose practices are incompatible with covenant life. The NT calls for a similar navigating of presence-within-the-world-without-conformity-to-it (Jn 17:15: &ldquo;not that you take them out of the world, but that you keep them from the evil one&rdquo;).</p>",
    "6": "<p>A shadow: intermarriage with the Canaanites and service to their gods — &ldquo;they took their daughters as wives for themselves, and gave their own daughters to their sons, and served their gods.&rdquo; The covenant purity of Israel is compromised by the most intimate human bond. The NT warns against the same: &ldquo;do not be unequally yoked with unbelievers&rdquo; (2 Cor 6:14), because the intimacy of partnership shapes the direction of worship.</p>",
    "7": "<p>A theme: &ldquo;they forgot the LORD their God and served the Baals and the Asheroth.&rdquo; Forgetting is the spiritual disease that idolatry produces: active replacement of YHWH with substitutes. The antidote in both Testaments is remembrance — the Passover, the Lord&rsquo;s Supper, the daily recitation of the Shema. Christ establishes the Supper precisely as an act of remembrance against spiritual amnesia: &ldquo;do this in remembrance of me&rdquo; (Luke 22:19).</p>",
    "8": "<p>A theme: YHWH&rsquo;s anger is &ldquo;kindled&rdquo; (<em>ḥārāh</em>) and he &ldquo;sold&rdquo; them to Cushan-rishathaim eight years. Divine anger as the covenantal consequence of apostasy is part of the judge cycle&rsquo;s grammar; YHWH&rsquo;s involvement in the oppression is not abandonment but active discipline. The eight-year span is the shortest oppression period in Judges — but even eight years of servitude is severe. The urgency of the deliverer needed is proportional to the severity of the bondage.</p>",
    "9": "<p>A type: &ldquo;when the people of Israel cried out to the LORD, the LORD raised up a deliverer for the people of Israel, who saved them — Othniel the son of Kenaz.&rdquo; This is the deliverer-type in its purest form: the cry of need, the divine response, the raising up of a specific person. The cry (<em>zaʿaq</em>) is a technical term for distress-petition; YHWH hears and acts by raising up (<em>qûm</em>, causing to stand up) his appointed deliverer. The NT&rsquo;s declaration that God &ldquo;raised up&rdquo; Christ from the dead (Acts 2:32) uses the same conceptual framework — the ultimate deliverer raised up in response to the human need for redemption from death.</p>",
    "10": "<p>A type: &ldquo;the Spirit of the LORD was upon him, and he judged Israel. He went out to war, and the LORD gave Cushan-rishathaim into his hand.&rdquo; Othniel is the cleanest judge-type: Spirit-anointed, legally judging, militarily victorious — all by YHWH&rsquo;s enabling. Each element maps directly onto Christ: the Spirit descends upon him at his baptism (Matt 3:16); he judges with divine authority (Jn 5:22); he conquers the enemy through his death and resurrection. Isa 61:1, cited by Jesus in the Nazareth synagogue (Luke 4:18), describes the Spirit-anointed deliverer that Othniel anticipates.</p>",
    "11": "<p>A shadow: &ldquo;the land had rest forty years.&rdquo; The forty-year Sabbath-rest under Othniel evokes the wilderness generation (40 years) and Moses&rsquo; generational spans; forty is the biblical number of completion and testing. The rest is real but temporary — it ends with Othniel&rsquo;s death. The Hebrews commentary on the Sabbath rest (Heb 4:1-11) is clear: the rest that Joshua and the judges provided was not the final rest; &ldquo;there remains a Sabbath rest for the people of God&rdquo; — found only in Christ.</p>",
    "12": "<p>A theme: &ldquo;the people of Israel again did what was evil.&rdquo; The word &ldquo;again&rdquo; (<em>wayyôsipû</em>, they added/continued) marks the cycle&rsquo;s resumption after the rest. Each resumption of the cycle deepens the reader&rsquo;s sense of the spiral — Israel cannot sustain covenant faithfulness through their own will. The escalating apostasy documents the need for a regenerating work that changes the will itself (Ezek 36:26-27; Jn 3:3-8).</p>",
    "13": "<p>A theme: YHWH strengthens Eglon of Moab, who recruits Ammonites and Amalekites and defeats Israel, taking the city of palms (Jericho). The divinely strengthened enemy is the instrument of covenant discipline. The city of palms — associated with the conquest&rsquo;s greatest victory — falls again into enemy hands, demonstrating that no past victory secures present faithfulness. The NT equivalent: past conversion does not guarantee ongoing discipleship; &ldquo;work out your own salvation with fear and trembling&rdquo; (Phil 2:12).</p>",
    "14": "<p>A theme: eighteen years of servitude to Moab. The extended oppression (longer than the eight years under Cushan) signals that the second cycle is worse. The escalation of oppression throughout Judges follows the escalation of apostasy, pointing toward the need for a deliverer who does not merely alleviate but permanently ends the cycle.</p>",
    "15": "<p>A type: Israel cries out again, and YHWH raises up Ehud the son of Gera — &ldquo;a left-handed man&rdquo; (literally &ldquo;a man bound/restricted in his right hand,&rdquo; <em>ʾitter yad-yəmînô</em>). God&rsquo;s deliberate choice of the weaker vessel (the left-handed was a disadvantage in ancient combat) anticipates the Pauline theology of divine power through human weakness: &ldquo;God chose what is weak in the world to shame the strong&rdquo; (1 Cor 1:27). The deliverer is unexpected; so is Christ — &ldquo;can anything good come out of Nazareth?&rdquo; (Jn 1:46).</p>",
    "16": "<p>A shadow: Ehud&rsquo;s double-edged sword, hidden on his right thigh and drawn with his left hand, is the instrument of deliverance. The double-edged sword as an image for the Word of God — &ldquo;the word of God is living and active, sharper than any two-edged sword&rdquo; (Heb 4:12) — gives the weapon symbolic weight. Ehud&rsquo;s unexpected instrument recalls the divine pattern of using what appears weak or unsuitable to accomplish what no conventional weapon could.</p>",
    "17": "<p>A theme: the presentation of tribute to Eglon — &ldquo;a very fat man&rdquo; — establishes the scene. The gross physicality of the oppressor (his obesity becomes the detail that makes the assassination possible in v22) is a narrative device that makes him humanly contemptible and the deliverance humanly satisfying. The narrator is not squeamish; the reality of oppressive power and its physical embodiment are honestly portrayed.</p>",
    "18": "<p>A theme: Ehud sends the tribute-bearers away after the presentation. He acts alone in the assassination — no witnesses, no army. The pattern of the solitary deliverer acting in secret recurs throughout Scripture: Gideon reducing his army (ch7), Samson alone against the Philistines. Christ enters the decisive battle of Gethsemane and the cross alone; &ldquo;I looked, but there was no one to help&rdquo; (Isa 63:5).</p>",
    "19": "<p>A shadow: &ldquo;I have a secret message for you, O king.&rdquo; The Hebrew <em>daḇar-sēter</em> (secret word/thing) carries double meaning: a word of God that is also a physical &ldquo;word&rdquo; (the sword). The divine word comes as revelation but also as judgment. The NT presents Christ as the Word of God (Jn 1:1) whose coming is both revelation and judgment: &ldquo;for judgment I came into this world&rdquo; (Jn 9:39).</p>",
    "20": "<p>A shadow: &ldquo;I have a message from God for you&rdquo; — Ehud&rsquo;s words are literally true; he is YHWH&rsquo;s instrument carrying YHWH&rsquo;s judgment. Eglon rises to receive the &ldquo;word of God&rdquo; — and receives a literal blade. The irony is sharp: the oppressor who made Israel his subjects rises in respect for the divine word, only to receive it as judgment. The scene anticipates the judgment that comes on all who honor God merely with their lips (Isa 29:13; Matt 15:8) while continuing in opposition to his purposes.</p>",
    "21": "<p>A theme: the sudden execution — Ehud&rsquo;s left hand draws the blade from his right thigh and thrusts it into Eglon&rsquo;s belly. The reversal of handedness (left-handed warrior drawing from the right side) is the surprise that makes the assassination possible. Divine deliverance regularly works through the reversal of expectations: the younger over the elder (Jacob), the small over the great (David and Goliath), the weak over the mighty (Christ&rsquo;s cross defeating death).</p>",
    "22": "<p>A theme: the sword sinks in completely — &ldquo;the dirt came out.&rdquo; The completeness of the fatal blow is emphasized: nothing is left undone. Christ&rsquo;s declaration &ldquo;it is finished&rdquo; (<em>tetelestai</em>, Jn 19:30) is the NT equivalent — the work of redemption is complete, nothing partial, nothing requiring supplementation.</p>",
    "23": "<p>A theme: Ehud escapes through the <em>misdərôn</em> (vestibule/porch) and locks the doors — creating the delay that enables his escape (vv.24-26). The divinely timed exit from the site of judgment is a recurring motif: Lot escaping Sodom (Gen 19), Israel crossing the Red Sea, and ultimately Christ&rsquo;s resurrection — escaping death and leaving the tomb behind.</p>",
    "24": "<p>A theme: the servants assume Eglon is relieving himself in the cool chamber — a moment of dark comedy. Their assumption delays the discovery and enables Ehud&rsquo;s escape. The enemies of God&rsquo;s purposes are confused about what has happened; the divine plan proceeds while they wait in bewilderment. This pattern of enemy confusion enabling deliverance appears in the Easter narrative: &ldquo;they sealed the tomb&rdquo; (Matt 27:66) thinking the story was over.</p>",
    "25": "<p>A theme: the servants wait until they are embarrassed, then take the key and find Eglon dead. The discovery comes too late to prevent the deliverer&rsquo;s escape. The enemies&rsquo; slowness to understand what has happened allows the work of God to reach completion before opposition can organize. The NT parallel: those who sought to stop the resurrection by sealing and guarding the tomb found it empty — too late to prevent what had already been accomplished.</p>",
    "26": "<p>A theme: while they delayed, Ehud escaped past the stone idols at Gilgal and reached safety. The idols at Gilgal — the site of Israel&rsquo;s covenant renewal after the Jordan crossing — stand as a sad commentary on the spiritual state of the land. The deliverer passes the corrupted sacred site on his way to freedom, representing the triumph of covenant fidelity over compromised religion.</p>",
    "27": "<p>A type: Ehud sounds the trumpet in the hill country of Ephraim, and the Israelites follow him into battle. The deliverer who accomplished the decisive blow now calls the community to participate in the victory. The pattern is identical to the resurrection and Pentecost sequence: Christ accomplishes the decisive victory, then the Spirit-sent proclamation (the &ldquo;trumpet&rdquo; of the gospel, 1 Cor 15:52; Rev 11:15) calls the community to follow him into the ongoing battle.</p>",
    "28": "<p>A type: &ldquo;Follow me, for the LORD has given your enemies the Moabites into your hand.&rdquo; Ehud&rsquo;s battle cry is the deliverer&rsquo;s call to discipleship in the moment of victory. Jesus&rsquo;s &ldquo;follow me&rdquo; calls are the NT expression of the same: the deliverer who has already won the decisive battle invites his people to join in the ongoing conquest (Matt 4:19; 16:24). The victory is certain because YHWH has already &ldquo;given&rdquo; the enemy.</p>",
    "29": "<p>A theme: ten thousand strong, able-bodied Moabites killed — &ldquo;not a man escaped.&rdquo; The completeness of the victory mirrors the promised total defeat of all enemies in the eschatological battle (Rev 19:11-21). The number ten thousand (a myriad) is the biblical superlative for a vast army; their complete defeat signals the thoroughness of YHWH&rsquo;s deliverance.</p>",
    "30": "<p>A shadow: &ldquo;Moab was subdued that day under the hand of Israel. And the land had rest for eighty years.&rdquo; The longest rest in Judges (80 years, a double generation) follows the Ehud deliverance. The extended rest is the closest the book comes to the permanent Sabbath-rest of the eschatological kingdom. But even 80 years ends; only the rest in Christ — the true Sabbath-rest that Heb 4:9 names — is permanent and unending.</p>",
    "31": "<p>A shadow: Shamgar kills six hundred Philistines with an oxgoad — an agricultural implement repurposed as a weapon. He also &ldquo;saved Israel.&rdquo; The pattern of extraordinary deliverance through unexpected means (an oxgoad; cf. Samson with a jawbone of a donkey, ch 15) anticipates the cross: the instrument of shame and death repurposed as the instrument of salvation. Paul calls the preaching of the cross &ldquo;folly&rdquo; to those who are perishing but &ldquo;the power of God&rdquo; to those being saved (1 Cor 1:18). God consistently chooses the instrument that human wisdom would reject.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'judges')
    merge_comm(existing, JUDGES)
    save_comm('mkt-christ', 'judges', existing)
    print('Judges 1-3 mkt-christ written.')

if __name__ == '__main__':
    main()
